	}
	// Spawn the promoted path's Bind-owned reader on the CURRENT Open span's delivery
	// signal; readersWG tracks it so a subsequent Close joins it (no goroutine leak).
	m.readersWG.Add(1)
	go m.readLoop(ps, m.deliverSignal)
	return nil
